const { Pool } = require('pg');
const express = require('express');

const app = express();
app.use(express.json());

// Secure approach: Use a dedicated application user with least-privilege access
// NEVER use the postgres superuser for application connections.
// 
// Prerequisites:
// 1. Create a dedicated database user with minimal required permissions:
//    CREATE USER app_service WITH PASSWORD '<strong_password>';
//    GRANT CONNECT ON DATABASE myapp_db TO app_service;
//    GRANT USAGE ON SCHEMA public TO app_service;
//    GRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO app_service;
//    ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO app_service;

const pool = new Pool({
  user: process.env.DB_APP_USER || 'app_service',
  host: process.env.DB_HOST || 'localhost',
  database: process.env.DB_NAME || 'myapp_db',
  password: process.env.DB_APP_PASSWORD,
  port: parseInt(process.env.DB_PORT, 10) || 5432,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 5000,
  ssl: process.env.DB_SSL === 'true' ? { rejectUnauthorized: true } : undefined,
});

// Validate that we are NOT connecting as a superuser at startup
async function validateConnectionSecurity() {
  let client;
  try {
    client = await pool.connect();
    const result = await client.query('SELECT current_user, usesuper FROM pg_user WHERE usename = current_user');
    if (result.rows.length > 0 && result.rows[0].usesuper === true) {
      console.error('SECURITY ERROR: Application is connected as a superuser. This is not allowed.');
      console.error('Please configure a dedicated application user with least-privilege permissions.');
      process.exit(1);
    }
    console.log(`Database connected securely as user: ${result.rows[0].current_user} (superuser: ${result.rows[0].usesuper})`);
  } catch (err) {
    console.error('Failed to validate database connection security:', err.message);
    process.exit(1);
  } finally {
    if (client) client.release();
  }
}

