app.post('/api/orders', async (req, res) => {
  const client = await pool.connect();
  try {
    const { user_id, product_id, quantity } = req.body;
    const parsedUserId = parseInt(user_id, 10);
    const parsedProductId = parseInt(product_id, 10);
    const parsedQuantity = parseInt(quantity, 10);
    if (isNaN(parsedUserId) || parsedUserId <= 0 ||
        isNaN(parsedProductId) || parsedProductId <= 0 ||
        isNaN(parsedQuantity) || parsedQuantity <= 0) {
      return res.status(400).json({ error: 'Valid user_id, product_id, and quantity are required' });
    }

    await client.query('BEGIN');

    const productResult = await client.query(
      'SELECT id, price, stock FROM products WHERE id = $1 FOR UPDATE',
      [parsedProductId]
    );
    if (productResult.rows.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({ error: 'Product not found' });
    }

    const product = productResult.rows[0];
    if (product.stock < parsedQuantity) {
      await client.query('ROLLBACK');
      return res.status(400).json({ error: 'Insufficient stock' });
    }

    const totalPrice = product.price * parsedQuantity;

    const orderResult = await client.query(
      `INSERT INTO orders (user_id, product_id, quantity, total_price, status, created_at)
       VALUES ($1, $2, $3, $4, 'pending', NOW())
       RETURNING id, user_id, product_id, quantity, total_price, status, created_at`,
      [parsedUserId, parsedProductId, parsedQuantity, totalPrice]
    );

    await client.query(
      'UPDATE products SET stock = stock - $1 WHERE id = $2',
      [parsedQuantity, parsedProductId]
    );

    await client.query('COMMIT');
    res.status(201).json({ data: orderResult.rows[0] });
  } catch (err) {
    await client.query('ROLLBACK');
    if (err.code === '23503') {
      return res.status(400).json({ error: 'Referenced user or product does not exist' });
    }
    console.error('Error creating order:', err.message);
    res.status(500).json({ error: 'Internal server error' });
  } finally {
    client.release();
  }
});

